use std::{
    env, fs,
    path::{Path, PathBuf},
    process::Command,
};

const RERUN_IF_CHANGED: &[&str] = &[
    "build.rs",
    "src/hal/linker/riscv64.ld.template",
    "src/hal/linker/loongarch64.ld.template",
    "../user/init/Cargo.toml",
    "../user/init/Cargo.lock",
    "../user/init/build.rs",
    "../user/init/src/main.rs",
    "../user/init/linker/riscv64.ld",
    "../user/init/linker/loongarch64.ld",
    "../user/fs_smoke/Cargo.toml",
    "../user/fs_smoke/Cargo.lock",
    "../user/fs_smoke/build.rs",
    "../user/fs_smoke/src/main.rs",
    "../user/fs_smoke/linker/riscv64.ld",
    "../user/fs_smoke/linker/loongarch64.ld",
    "../user/fs_exec_probe/Cargo.toml",
    "../user/fs_exec_probe/Cargo.lock",
    "../user/fs_exec_probe/build.rs",
    "../user/fs_exec_probe/src/main.rs",
    "../user/fs_exec_probe/linker/riscv64.ld",
    "../user/fs_exec_probe/linker/loongarch64.ld",
];

fn main() {
    RERUN_IF_CHANGED
        .iter()
        .copied()
        .for_each(|path| println!("cargo:rerun-if-changed={path}"));

    let target_arch = env::var("CARGO_CFG_TARGET_ARCH").expect("missing CARGO_CFG_TARGET_ARCH");
    let out_dir = PathBuf::from(env::var("OUT_DIR").expect("missing OUT_DIR"));

    let config = link_config_for_target_arch(&target_arch);

    generate_linker_script(&out_dir, &config);
    generate_rust_constants(&out_dir, &config);
    build_and_embed_user_programs(&out_dir);
}

fn link_config_for_target_arch(target_arch: &str) -> LinkConfig {
    match target_arch {
        "riscv64" => LinkConfig {
            kernel_lma: 0x8020_0000,
            kernel_vma_offset: 0xffff_ffff_0000_0000,
            phys_linear_mapping_base_vaddr: 0xffff_8000_0000_0000,
            mmio_direct_base_vaddr: 0xffff_8000_0000_0000,
            loongarch_dmw0_config: None,
            loongarch_dmw1_config: None,
            loongarch_dmw2_config: None,
            template_path: Path::new("src/hal/linker/riscv64.ld.template"),
            linker_filename: "riscv64-linker.ld",
        },
        "loongarch64" => LinkConfig {
            kernel_lma: 0x0020_0000,
            kernel_vma_offset: 0x9000_0000_0000_0000,
            phys_linear_mapping_base_vaddr: 0x9000_0000_0000_0000,
            mmio_direct_base_vaddr: 0x8000_0000_0000_0000,
            loongarch_dmw0_config: Some(0x9000_0000_0000_0011),
            loongarch_dmw1_config: Some(0x0000_0000_0000_0011),
            loongarch_dmw2_config: Some(0x8000_0000_0000_0001),
            template_path: Path::new("src/hal/linker/loongarch64.ld.template"),
            linker_filename: "loongarch64-linker.ld",
        },
        other => panic!("unsupported target arch for linker generation: {other}"),
    }
}

struct LinkConfig {
    kernel_lma: usize,
    kernel_vma_offset: usize,
    phys_linear_mapping_base_vaddr: usize,
    mmio_direct_base_vaddr: usize,
    loongarch_dmw0_config: Option<usize>,
    loongarch_dmw1_config: Option<usize>,
    loongarch_dmw2_config: Option<usize>,
    template_path: &'static Path,
    linker_filename: &'static str,
}

fn generate_linker_script(out_dir: &Path, config: &LinkConfig) {
    let template = fs::read_to_string(config.template_path).unwrap_or_else(|err| {
        panic!(
            "failed to read linker template {:?}: {err}",
            config.template_path
        )
    });
    let script = template
        .replace("@KERNEL_LMA@", &format!("{:#x}", config.kernel_lma))
        .replace(
            "@KERNEL_VMA_OFFSET@",
            &format!("{:#x}", config.kernel_vma_offset),
        );

    let linker_path = out_dir.join(config.linker_filename);
    fs::write(&linker_path, script).unwrap_or_else(|err| {
        panic!(
            "failed to write generated linker script {:?}: {err}",
            linker_path
        )
    });

    println!(
        "cargo:rustc-link-arg-bin=nexus-os=-T{}",
        linker_path.display()
    );
}

fn generate_rust_constants(out_dir: &Path, config: &LinkConfig) {
    let mut constants = format!(
        "pub const KERNEL_LMA: usize = {:#x};\n\
         pub const KERNEL_VMA_OFFSET: usize = {:#x};\n\
         pub const PHYS_LINEAR_MAPPING_BASE_VADDR: usize = {:#x};\n\
         pub const MMIO_DIRECT_BASE_VADDR: usize = {:#x};\n",
        config.kernel_lma,
        config.kernel_vma_offset,
        config.phys_linear_mapping_base_vaddr,
        config.mmio_direct_base_vaddr,
    );

    if let Some(value) = config.loongarch_dmw0_config {
        constants.push_str(&format!(
            "pub const LOONGARCH_DMW0_CONFIG: usize = {value:#x};\n"
        ));
    }
    if let Some(value) = config.loongarch_dmw1_config {
        constants.push_str(&format!(
            "pub const LOONGARCH_DMW1_CONFIG: usize = {value:#x};\n"
        ));
    }
    if let Some(value) = config.loongarch_dmw2_config {
        constants.push_str(&format!(
            "pub const LOONGARCH_DMW2_CONFIG: usize = {value:#x};\n"
        ));
    }

    let constants_path = out_dir.join("arch_boot_constants.rs");
    fs::write(&constants_path, constants).unwrap_or_else(|err| {
        panic!(
            "failed to write generated constants {:?}: {err}",
            constants_path
        )
    });
}

/// 构建内置用户程序，并把 ELF 复制到构建输出目录。
fn build_and_embed_user_programs(out_dir: &Path) {
    let kernel_target_dir = cargo_target_dir_from_out_dir(out_dir);
    let user_target_dir = kernel_target_dir.join("user-programs");
    build_and_embed_user_program(
        out_dir,
        &user_target_dir,
        "../user/init",
        "init",
        "nexus-user-init.elf",
        "NEXUS_USER_INIT_ELF",
    );
    build_and_embed_user_program(
        out_dir,
        &user_target_dir,
        "../user/fs_smoke",
        "fs_smoke",
        "nexus-user-fs-smoke.elf",
        "NEXUS_USER_FS_SMOKE_ELF",
    );
    build_and_embed_user_program(
        out_dir,
        &user_target_dir,
        "../user/fs_exec_probe",
        "fs_exec_probe",
        "nexus-user-fs-exec-probe.elf",
        "NEXUS_USER_FS_EXEC_PROBE_ELF",
    );
}

/// 从 Cargo 的 `OUT_DIR` 中恢复外层 target-dir 路径。
fn cargo_target_dir_from_out_dir(out_dir: &Path) -> PathBuf {
    // Cargo 的 OUT_DIR 一般形如：
    //   <target-dir>/<triple>/<profile>/build/<pkg-hash>/out
    //
    // 这里取出 <target-dir>，供构建脚本内部启动的用户程序构建使用。
    // 容器构建可以把该目录指向容器内路径，避免复用挂载工作区里的宿主机构建缓存。
    //
    // Cargo 改变 OUT_DIR 布局时，继续推断会写错目录；这里直接暴露异常。
    out_dir
        .ancestors()
        .nth(5)
        .map(Path::to_path_buf)
        .unwrap_or_else(|| panic!("unexpected OUT_DIR layout: {out_dir:?}"))
}

/// 构建单个用户程序，将 ELF 复制到输出目录，并设置编译期环境变量。
fn build_and_embed_user_program(
    out_dir: &Path,
    target_dir: &Path,
    user_program_dir: &str,
    bin_name: &str,
    out_filename: &str,
    env_key: &str,
) {
    let target = env::var("TARGET").expect("missing TARGET");
    let profile = env::var("PROFILE").expect("missing PROFILE");
    let cargo = env::var("CARGO").unwrap_or_else(|_| "cargo".into());

    let manifest_dir =
        PathBuf::from(env::var("CARGO_MANIFEST_DIR").expect("missing CARGO_MANIFEST_DIR"));
    let user_manifest = manifest_dir.join(user_program_dir).join("Cargo.toml");
    let workspace_root = manifest_dir
        .parent()
        .unwrap_or_else(|| panic!("unexpected CARGO_MANIFEST_DIR: {manifest_dir:?}"));

    let mut cmd = Command::new(cargo);
    cmd.args([
        "build",
        "--manifest-path",
        user_manifest
            .to_str()
            .expect("user init Cargo.toml path is not UTF-8"),
        "--target",
        &target,
    ]);
    cmd.current_dir(workspace_root);
    // 用户程序使用外层 target-dir 的子目录。
    // Cargo 会对 target-dir 加全局锁；若内部构建复用同一目录，会等待外层构建释放锁。
    // 子目录既避开同一把锁，也保留外层构建目录的隔离策略。
    cmd.args([
        "--target-dir",
        target_dir.to_str().expect("target dir is not UTF-8"),
    ]);
    match profile.as_str() {
        "debug" => {}
        "release" => {
            cmd.arg("--release");
        }
