#![no_std]
#![no_main]

extern crate alloc;
extern crate nexus_os as nexus;

#[cfg(not(feature = "ktest"))]
mod oscomp_runner;
use core::panic::PanicInfo;
use core::sync::atomic::{AtomicU64, Ordering};

use nexus::hal::{cpu, power, smp, BootInfo, HartId, HartMask};
use nexus::mm;
use nexus::thread;

static PRINTED_MASK: AtomicU64 = AtomicU64::new(0);
const BOOT_WAIT_MAX_SPINS: usize = 20_000_000;

/// 把指定 hart 标记为已经完成启动输出。
fn mark_printed(hart_id: HartId) {
    PRINTED_MASK.fetch_or(HartMask::empty().insert(hart_id).bits(), Ordering::Release);
}

/// 等待目标 hart 集合都进入“已完成启动输出”状态。
///
/// 若在 `max_spins` 次自旋内全部到达，则返回当时观测到的完整位图；
/// 否则返回超时瞬间观测到的位图，供调用者继续判定。
#[inline]
fn wait_printed(mask: HartMask, max_spins: usize) -> HartMask {
    let want = mask.bits();
    for _ in 0..max_spins {
        let printed = PRINTED_MASK.load(Ordering::Acquire);
        if (printed & want) == want {
            return HartMask::from_bits(printed);
        }
        cpu::relax();
    }
    HartMask::from_bits(PRINTED_MASK.load(Ordering::Acquire))
}

/// 打印 panic 信息并关机，避免内核继续在失效状态下执行。
#[panic_handler]
fn panic(info: &PanicInfo) -> ! {
    nexus::printk::print(core::format_args!("[panic] {}\n", info));
    power::poweroff();
}

/// HAL 提供的内核主入口，转交给统一的启动主流程。
#[no_mangle]
fn __hal_kernel_main(boot: &'static BootInfo) -> ! {
    kernel_main(boot)
}

/// 在 boot hart 上完成内核初始化，并进入调度或用户态测试入口。
fn kernel_main(boot: &'static BootInfo) -> ! {
    let boot_hart = boot.cpu.boot_hart_id;

    nexus::logger::init_from_boot_info(boot);
    log::info!(
        "boot hart={} dtb={:?} mem_regions={}",
        boot_hart.as_usize(),
        boot.dtb_pa,
        boot.memory_regions.len()
    );
    mark_printed(boot_hart);

    mm::init(boot);
    thread::exception::install_kernel_trap_handler();
    // SAFETY: `mm::init()` 已经为本架构构造好可激活的 kernel page table；
    // boot hart 仍在可兼容的 low-link/DMW 执行环境中，切换后继续执行是安全的。
    unsafe { mm::kspace::activate_kernel_page_table_for_current_cpu(boot_hart) };
    nexus::smp::init_on_current_hart();

    // 先启用本地 timer tick，使用户态测试截止回调覆盖启动流程余下步骤。
    // 外部设备 IRQ 仍由对应驱动初始化路径启用，避免提前接收 virtio 中断。
    #[cfg(not(feature = "ktest"))]
    {
        nexus::hal::irq::enable_local();
        nexus::time::init();
        nexus::runner_timeout::install_global_timeout(
            oscomp_runner::config::runner_global_timeout_secs(),
        );
        nexus::time::enable_timer_interrupt_on_current_hart();
        log::info!(
            "time: early init ticks_per_second={} tick_hz={}",
            nexus::hal::time::ticks_per_second(),
            nexus::hal::time::KERNEL_TICK_HZ
        );
    }

    let report = smp::start_secondary_harts(boot);
    let expected_secondaries = report.target_mask;
    let expected_active = expected_secondaries.insert(boot_hart);

    let printed = wait_printed(expected_secondaries, BOOT_WAIT_MAX_SPINS);
    let final_kpt_active =
        mm::kspace::wait_until_kernel_page_table_active(expected_active, BOOT_WAIT_MAX_SPINS);
    assert_eq!(
        final_kpt_active.bits() & expected_active.bits(),
        expected_active.bits(),
        "not all expected harts switched to final kernel page table"
    );

    log::info!(
        "smp target=0x{:x} start_ok=0x{:x} active=0x{:x} printed=0x{:x}",
        report.target_mask.bits(),
        report.start_ok_mask.bits(),
        final_kpt_active.bits(),
        printed.bits()
    );

    // SAFETY: 此时所有 secondary CPU 已完成启动并切到 final KPT。
    unsafe {
        let reclaimed_bytes = mm::reclaim_kernel_boot_reclaimable_memory();
        log::debug!("reclaimed boot memory bytes={}", reclaimed_bytes);
        let reclaimed_boot_pt_bytes = mm::reclaim_boot_page_table_memory();
        log::debug!("reclaimed boot pt bytes={}", reclaimed_boot_pt_bytes);
    }

    #[cfg(feature = "ktest")]
    {
        nexus::ktest::run();
    }
    #[cfg(not(feature = "ktest"))]
    run_demo_threads(boot_hart)
}

/// 创建 init 内核线程并进入调度循环。
#[cfg(not(feature = "ktest"))]
fn run_demo_threads(boot_hart: HartId) -> ! {
    let affinity = HartMask::empty().insert(boot_hart);
    let _ = thread::KernelThreadOptions::new(oscomp_runner::init_thread)
        .name("init")
        .cpu_affinity(affinity)
        .spawn()
        .expect("failed to spawn init thread");
    thread::enter()
}

/// HAL 提供的次级 hart 入口，完成本 hart 的最小初始化后进入调度。
#[no_mangle]
fn __hal_kernel_secondary_main(hart_id: usize, _boot: &'static BootInfo) -> ! {
    nexus::logger::init_from_boot_info(_boot);
    // SAFETY: primary 在放行 secondary 之前已经完成 `mm::init()` 并发布 kernel page table；
    // secondary 仍处于 boot 兼容执行窗口，先切换到 final kernel page table 再进入上层逻辑。
    unsafe { mm::kspace::activate_kernel_page_table_for_current_cpu(HartId::new(hart_id)) };
    nexus::smp::init_on_current_hart();
    log::info!("hart {} online", hart_id);
    mark_printed(HartId::new(hart_id));
    thread::enter()
}

