const BOOTARGS_BUF_LEN: usize = 4096;

/// 读取启动命令行，并把结果交给调用方闭包处理。
///
/// 该函数向调用方提供命令行文本的只读视图，不泄露 DTB 或 `fw_cfg` 内部引用供长期保存。
/// 调用方应在闭包内解析或复制，避免把启动期内存布局细节扩散到上层模块。
pub fn with_bootargs<R>(read: impl FnOnce(Option<&str>) -> R) -> R {
    let Some(dtb_pa) = boot_info().dtb_pa else {
        return read(None);
    };

    if let Some(bootargs) = dtb_bootargs(dtb_pa) {
        return read(Some(bootargs));
    }

    let mut fw_cfg_bootargs = [0u8; BOOTARGS_BUF_LEN];
    read(boot::qemu_fw_cfg::read_named_file_from_dtb(
        dtb_pa,
        "opt/nexus.bootargs",
        &mut fw_cfg_bootargs,
    ))
}

/// 从 DTB `/chosen/bootargs` 读取启动命令行。
fn dtb_bootargs(dtb_pa: PhysAddr) -> Option<&'static str> {
    let dtb_ptr = phys_to_virt(dtb_pa).as_ptr::<u8>();
    // SAFETY: `dtb_pa` 来自启动协议解析后的 `BootInfo`，指向内核启动期间保持有效的 DTB。
    let fdt = unsafe { fdt::Fdt::from_ptr(dtb_ptr) }
        .unwrap_or_else(|_| panic!("invalid DTB at {:?}", dtb_pa));
    fdt.find_node("/chosen")
        .and_then(|chosen| chosen.property("bootargs"))
        .and_then(|prop| prop.as_str())
        .filter(|bootargs| !bootargs.is_empty())
}

