/// 内核态陷入保存的寄存器集合。
#[derive(Debug, Default, Clone, Copy)]
#[repr(C)]
pub struct TrapFrame {
    /// 通用寄存器。
    pub general: GeneralRegs,
    /// `sstatus`。
    pub sstatus: usize,
    /// `sepc`。
    pub sepc: usize,
}

/// 用户态保存上下文，与陷入帧布局一致。
#[derive(Debug, Clone, Copy)]
#[repr(C)]
pub(in crate::hal) struct RawUserContext {
    pub(in crate::hal) general: GeneralRegs,
    pub(in crate::hal) sstatus: usize,
    pub(in crate::hal) sepc: usize,
}

impl Default for RawUserContext {
    fn default() -> Self {
        // 返回用户态的最小 `sstatus` 基线：
        // - `SPP=0`：返回到 U-mode；
        // - `SPIE=1`：允许用户态期间的 S-mode 中断（timer 等）正常陷入。
        const SSTATUS_SPIE: usize = 1 << 5;
        Self {
            general: GeneralRegs::default(),
            sstatus: SSTATUS_SPIE,
            sepc: 0,
        }
    }
}

impl TrapFrame {
    /// 获取陷入返回地址（PC）。
    #[inline]
    pub fn pc(&self) -> usize {
        self.sepc
    }

    /// 设置陷入返回地址（PC）。
    #[inline]
    pub fn set_pc(&mut self, pc: usize) {
        self.sepc = pc;
    }

    /// 获取保存的栈指针。
    #[inline]
    pub fn sp(&self) -> usize {
        self.general.sp
    }

    /// 设置返回时将恢复的栈指针。
    #[inline]
    pub fn set_sp(&mut self, sp: usize) {
        self.general.sp = sp;
    }

    /// 获取系统调用参数寄存器（a0..a7）。
    #[inline]
    pub fn arg(&self, index: usize) -> usize {
        match index {
            0 => self.general.a0,
            1 => self.general.a1,
            2 => self.general.a2,
            3 => self.general.a3,
            4 => self.general.a4,
            5 => self.general.a5,
            6 => self.general.a6,
            7 => self.general.a7,
            _ => 0,
        }
    }

    /// 设置系统调用参数寄存器（a0..a7）。
    #[inline]
    pub fn set_arg(&mut self, index: usize, value: usize) {
        match index {
            0 => self.general.a0 = value,
            1 => self.general.a1 = value,
            2 => self.general.a2 = value,
            3 => self.general.a3 = value,
            4 => self.general.a4 = value,
            5 => self.general.a5 = value,
            6 => self.general.a6 = value,
            7 => self.general.a7 = value,
            _ => {}
        }
    }

    /// 返回本次异常关联的地址（`stval`）。
    #[inline]
    pub fn fault_addr(&self) -> usize {
        let _ = self;
        riscv::register::stval::read()
    }
}

impl RawUserContext {
    /// 进入用户态执行，并在陷入时返回。
    ///
    /// 返回后，本结构已被更新为陷入发生时的寄存器快照。
    pub(in crate::hal) fn run(&mut self) {
        // 切换 `sscratch` 并返回用户态前必须关闭本地中断，
        // 否则中断可能在 `sscratch` 交换窗口破坏约定。
        crate::hal::irq::disable_local();
        unsafe { run_user(self) }
    }
}

#[allow(improper_ctypes)]
extern "C" {
    fn trap_entry();
    fn run_user(regs: &mut RawUserContext);
}

