    unsafe { asm!("csrw sscratch, zero") }
}

/// 内核态陷入入口，由 `trap_entry` 调用。
///
/// 该符号只处理内核态陷入；用户态陷入不会走到这里。
#[no_mangle]
extern "C" fn trap_handler(tf: &mut TrapFrame) {
    const LINUX_EFAULT: isize = -14;

    let scause = scause::read();
    let code = scause.code();

    let Ok(cause) = Trap::<Interrupt, Exception>::try_from(scause.cause()) else {
        crate::hal::trap::dispatch_kernel_trap(
            tf,
            TrapCause::Exception {
                kind: ExceptionKind::Unknown,
                raw: code,
            },
        );
        return;
    };

    let cause = match cause {
        Trap::Interrupt(interrupt) => match interrupt {
            Interrupt::SupervisorTimer => {
                super::time::on_timer_interrupt(crate::hal::time::TickSource::Kernel);
                TrapCause::Interrupt {
                    kind: InterruptKind::Timer,
                    raw: code,
                }
            }
            Interrupt::SupervisorExternal => TrapCause::Interrupt {
                kind: InterruptKind::External,
                raw: code,
            },
            Interrupt::SupervisorSoft => {
                crate::smp::ack_ipi_on_current_hart();
                crate::smp::on_ipi();
                TrapCause::Interrupt {
                    kind: InterruptKind::Software,
                    raw: code,
                }
            }
        },
        Trap::Exception(exception) => match exception {
            Exception::UserEnvCall | Exception::SupervisorEnvCall => TrapCause::Exception {
                kind: ExceptionKind::Syscall,
                raw: code,
            },
            Exception::InstructionPageFault
            | Exception::LoadPageFault
            | Exception::StorePageFault => {
                // 缺页异常先查故障修复表；命中时跳到修复地址并返回错误码。
                if let Some(fixup) = crate::hal::trap::ex_table_lookup(tf.sepc) {
                    tf.sepc = fixup;
                    tf.set_arg(0, LINUX_EFAULT as usize);
                    return;
                }
                TrapCause::Exception {
                    kind: ExceptionKind::PageFault,
                    raw: code,
                }
            }
            Exception::IllegalInstruction => TrapCause::Exception {
                kind: ExceptionKind::IllegalInstruction,
                raw: code,
            },
            Exception::Breakpoint => TrapCause::Exception {
                kind: ExceptionKind::Breakpoint,
                raw: code,
            },
            _ => TrapCause::Exception {
                kind: ExceptionKind::Unknown,
                raw: code,
            },
        },
    };

    crate::hal::trap::dispatch_kernel_trap(tf, cause);
}

