bitflags::bitflags! {
    #[derive(Clone, Copy, Debug, PartialEq, Eq)]
    struct PageTableFlags: usize {
        const VALID = 1 << 0;
        const READABLE = 1 << 1;
        const WRITABLE = 1 << 2;
        const EXECUTABLE = 1 << 3;
        const USER = 1 << 4;
        const GLOBAL = 1 << 5;
        const ACCESSED = 1 << 6;
        const DIRTY = 1 << 7;
        const RSV1 = 1 << 8;
        const RSV2 = 1 << 9;
        const PBMT_NC = 1 << 61;
        const PBMT_IO = 1 << 62;
        const NAPOT = 1 << 63;
    }
}

/// 将 `from` 表示法里的单个 flag 位投影到 `to` 表示法里的对应 flag 位。
macro_rules! parse_flag_bits {
    ($val:expr, $from:expr, $to:expr) => {
        ((($val as usize & $from.bits() as usize) >> ($from.bits() as usize).ilog2())
            << ($to.bits() as usize).ilog2())
    };
}

/// RISC-V 页表项。
#[derive(Clone, Copy, Debug, Default)]
#[repr(transparent)]
pub struct PageTableEntry(usize);

// SAFETY: `PageTableEntry` 是 `usize` 的透明封装，无 padding，任意 bit pattern 均有效。
unsafe impl crate::Pod for PageTableEntry {}

impl crate::mm::io::PodOnce for PageTableEntry {}

impl PageTableEntry {
    const PHYS_ADDR_MASK: usize = 0x003f_ffff_ffff_fc00;

    fn new_paddr(paddr: PhysAddr) -> Self {
        let ppn = paddr.as_usize() >> 12;
        Self(ppn << 10)
    }
}

impl PageTableEntryTrait for PageTableEntry {
    fn is_present(&self) -> bool {
        (self.0 & PageTableFlags::VALID.bits()) != 0
    }

    fn new_leaf(paddr: PhysAddr, _level: PagingLevel, prop: PageProperty) -> Self {
        let mut pte = Self::new_paddr(paddr);
        pte.set_prop(prop);
        pte
    }

    fn new_pt_node(paddr: PhysAddr) -> Self {
        let pte = Self::new_paddr(paddr);
        Self(pte.0 | PageTableFlags::VALID.bits())
    }

    fn paddr(&self) -> PhysAddr {
        let ppn = (self.0 & Self::PHYS_ADDR_MASK) >> 10;
        PhysAddr::new(ppn << 12)
    }

    fn prop(&self) -> PageProperty {
        let flags = parse_flag_bits!(self.0, PageTableFlags::READABLE, PageFlags::R)
            | parse_flag_bits!(self.0, PageTableFlags::WRITABLE, PageFlags::W)
            | parse_flag_bits!(self.0, PageTableFlags::EXECUTABLE, PageFlags::X)
            | parse_flag_bits!(self.0, PageTableFlags::ACCESSED, PageFlags::ACCESSED)
            | parse_flag_bits!(self.0, PageTableFlags::DIRTY, PageFlags::DIRTY)
            | parse_flag_bits!(self.0, PageTableFlags::RSV1, PageFlags::AVAIL1)
            | parse_flag_bits!(self.0, PageTableFlags::RSV2, PageFlags::AVAIL2);
        let priv_flags = parse_flag_bits!(self.0, PageTableFlags::USER, PrivilegedPageFlags::USER)
            | parse_flag_bits!(self.0, PageTableFlags::GLOBAL, PrivilegedPageFlags::GLOBAL);

        let pbmt_mask = PageTableFlags::PBMT_IO.bits() | PageTableFlags::PBMT_NC.bits();
        let cache = if (self.0 & pbmt_mask) != 0 {
            CachePolicy::Uncacheable
        } else {
            CachePolicy::Writeback
        };

        PageProperty {
            has_map: self.is_present(),
            flags: PageFlags::from_bits(flags as u8).expect("RISC-V pte flags must fit PageFlags"),
            cache,
            priv_flags: PrivilegedPageFlags::from_bits(priv_flags as u8)
                .expect("RISC-V pte priv_flags must fit PrivilegedPageFlags"),
        }
    }

    fn set_prop(&mut self, prop: PageProperty) {
        let mut raw =
            (if prop.has_map {
                PageTableFlags::VALID.bits()
            } else {
                0
            }) | parse_flag_bits!(prop.flags.bits(), PageFlags::R, PageTableFlags::READABLE)
                | parse_flag_bits!(prop.flags.bits(), PageFlags::W, PageTableFlags::WRITABLE)
                | parse_flag_bits!(prop.flags.bits(), PageFlags::X, PageTableFlags::EXECUTABLE)
                | parse_flag_bits!(
                    prop.flags.bits(),
                    PageFlags::ACCESSED,
                    PageTableFlags::ACCESSED
                )
                | parse_flag_bits!(prop.flags.bits(), PageFlags::DIRTY, PageTableFlags::DIRTY)
                | parse_flag_bits!(prop.flags.bits(), PageFlags::AVAIL1, PageTableFlags::RSV1)
                | parse_flag_bits!(prop.flags.bits(), PageFlags::AVAIL2, PageTableFlags::RSV2)
                | parse_flag_bits!(
                    prop.priv_flags.bits(),
                    PrivilegedPageFlags::USER,
                    PageTableFlags::USER
                )
                | parse_flag_bits!(
                    prop.priv_flags.bits(),
                    PrivilegedPageFlags::GLOBAL,
                    PageTableFlags::GLOBAL
                );

        match prop.cache {
            CachePolicy::Writeback => {}
            CachePolicy::Uncacheable => {
                raw |= PageTableFlags::PBMT_IO.bits();
            }
            CachePolicy::WriteCombining
            | CachePolicy::WriteProtected
            | CachePolicy::Writethrough => {
                panic!("unsupported cache policy on RISC-V")
            }
        }

        self.0 = (self.0 & Self::PHYS_ADDR_MASK) | raw;
    }

    fn set_paddr(&mut self, paddr: PhysAddr) {
        self.0 = (self.0 & !Self::PHYS_ADDR_MASK) | Self::new_paddr(paddr).0;
    }

    fn is_leaf(&self, level: PagingLevel) -> bool {
        let rwx = PageTableFlags::READABLE | PageTableFlags::WRITABLE | PageTableFlags::EXECUTABLE;
        level == 1 || (self.0 & rwx.bits()) != 0
    }

    fn as_usize(self) -> usize {
        self.0
    }

    fn from_usize(raw: usize) -> Self {
        Self(raw)
    }
}

/// 激活指定页表根。
