//! 陷入归一化与向上回调
//!
//! 架构层把原始陷入解析成 `TrapCause`，本模块保存内核态处理函数。
//! 上下文切换由线程调度入口完成，陷入分发本身不返回新的执行上下文。

use crate::hal::base::fault::ExTableEntry;
use crate::hal::imp::arch::TrapFrame as ArchTrapFrame;
use crate::sync::Once;

/// 目标架构的 `TrapFrame` 类型。
pub type TrapFrame = ArchTrapFrame;

#[derive(Clone, Copy, Debug)]
pub enum InterruptKind {
    Timer,
    External,
    Software,
    Unknown,
}

#[derive(Clone, Copy, Debug)]
pub enum ExceptionKind {
    Syscall,
    PageFault,
    Fault,
    Breakpoint,
    IllegalInstruction,
    Unknown,
}

#[derive(Clone, Copy, Debug)]
pub enum TrapCause {
    Interrupt { kind: InterruptKind, raw: usize },
    Exception { kind: ExceptionKind, raw: usize },
}

pub type KernelTrapHandler = fn(tf: &mut TrapFrame, cause: TrapCause);

fn default_kernel_trap(tf: &mut TrapFrame, cause: TrapCause) {
    match cause {
        TrapCause::Interrupt { .. } => {
            // 计时器中断已由架构层完成确认和重编程；内核态处理函数注册前不改变执行流。
            let _ = tf;
        }
        TrapCause::Exception { .. } => {
            // 异常默认不可恢复：进入死循环等待调试接管。
            let _ = tf;
            loop {
                crate::hal::cpu::relax();
            }
        }
    }
}

static KERNEL_TRAP_HANDLER: Once<KernelTrapHandler> = Once::new();

static TRAP_NOTIFIER: Once<fn(TrapCause)> = Once::new();

/// 注册 trap 通知回调。
///
/// 回调运行在 trap 上下文，必须短小且不可阻塞。调用方应把它限定为
/// 全局观察或终止动作，不在这里执行子系统状态推进。
pub fn register_trap_notifier(handler: fn(TrapCause)) {
    let _ = TRAP_NOTIFIER.call_once(|| handler);
}

/// 通知一次架构层已经解析的 trap。
pub(crate) fn notify_trap(cause: TrapCause) {
    let Some(handler) = TRAP_NOTIFIER.get().copied() else {
        return;
    };
    handler(cause);
}

/// 注册内核态陷入处理函数。
///
/// 调用方应在开启中断之前完成注册。
pub fn register_kernel_trap_handler(handler: KernelTrapHandler) {
    KERNEL_TRAP_HANDLER.call_once(|| handler);
}

/// 分发架构层解析后的陷入。
pub(crate) fn dispatch_kernel_trap(tf: &mut TrapFrame, cause: TrapCause) {
    notify_trap(cause);
    let handler = KERNEL_TRAP_HANDLER
        .get()
        .copied()
        .unwrap_or(default_kernel_trap);
    handler(tf, cause);
}

