/// 在 `ex_table` 中查找指定 PC 的修复地址。
pub fn ex_table_lookup(pc: usize) -> Option<usize> {
    // SAFETY: 链接脚本提供连续数组。
    unsafe {
        let start = &__hal_ex_table_start as *const _ as usize;
        let end = &__hal_ex_table_end as *const _ as usize;
        let len = (end - start) / core::mem::size_of::<ExTableEntry>();
        let table = core::slice::from_raw_parts(start as *const ExTableEntry, len);
        table.iter().find(|e| e.insn == pc).map(|e| e.fixup)
    }
}

