static VMO_ACCOUNTING_EVENT_SEQ: AtomicUsize = AtomicUsize::new(0);
static VMO_ACCOUNTING_EVENT_SLOT_SEQ: [AtomicUsize; VMO_ACCOUNTING_EVENT_RING_LEN] =
    [const { AtomicUsize::new(0) }; VMO_ACCOUNTING_EVENT_RING_LEN];
static VMO_ACCOUNTING_EVENT_KIND: [AtomicUsize; VMO_ACCOUNTING_EVENT_RING_LEN] =
    [const { AtomicUsize::new(0) }; VMO_ACCOUNTING_EVENT_RING_LEN];
static VMO_ACCOUNTING_EVENT_PTR: [AtomicUsize; VMO_ACCOUNTING_EVENT_RING_LEN] =
    [const { AtomicUsize::new(0) }; VMO_ACCOUNTING_EVENT_RING_LEN];
static VMO_ACCOUNTING_EVENT_COUNT: [AtomicUsize; VMO_ACCOUNTING_EVENT_RING_LEN] =
    [const { AtomicUsize::new(0) }; VMO_ACCOUNTING_EVENT_RING_LEN];
static VMO_ACCOUNTING_EVENT_PAGE_LEN: [AtomicUsize; VMO_ACCOUNTING_EVENT_RING_LEN] =
    [const { AtomicUsize::new(0) }; VMO_ACCOUNTING_EVENT_RING_LEN];
static VMO_ACCOUNTING_EVENT_SIZE: [AtomicUsize; VMO_ACCOUNTING_EVENT_RING_LEN] =
    [const { AtomicUsize::new(0) }; VMO_ACCOUNTING_EVENT_RING_LEN];
static VMO_ACCOUNTING_EVENT_FLAGS: [AtomicUsize; VMO_ACCOUNTING_EVENT_RING_LEN] =
    [const { AtomicUsize::new(0) }; VMO_ACCOUNTING_EVENT_RING_LEN];

/// 输出最近的 VMO 提交页计数事件。
pub(crate) fn log_recent_vmo_accounting_events() {
    let latest = VMO_ACCOUNTING_EVENT_SEQ.load(Ordering::Relaxed);
    let first = latest.saturating_sub(VMO_ACCOUNTING_EVENT_RING_LEN - 1);
    for seq in first..=latest {
        if seq == 0 {
            continue;
        }
        let index = seq % VMO_ACCOUNTING_EVENT_RING_LEN;
        if VMO_ACCOUNTING_EVENT_SLOT_SEQ[index].load(Ordering::Relaxed) != seq {
            continue;
        }
        let kind = match VMO_ACCOUNTING_EVENT_KIND[index].load(Ordering::Relaxed) {
            VMO_EVENT_CREATE => "create",
            VMO_EVENT_COMMIT => "commit",
            VMO_EVENT_DECOMMIT => "decommit",
            VMO_EVENT_DROP => "drop",
            _ => "unknown",
        };
        log::error!(
            "[vmo] accounting recent seq={} kind={} vmo={:#x} count={} pages_len={} size={} flags={:#x}",
            seq,
            kind,
            VMO_ACCOUNTING_EVENT_PTR[index].load(Ordering::Relaxed),
            VMO_ACCOUNTING_EVENT_COUNT[index].load(Ordering::Relaxed),
            VMO_ACCOUNTING_EVENT_PAGE_LEN[index].load(Ordering::Relaxed),
            VMO_ACCOUNTING_EVENT_SIZE[index].load(Ordering::Relaxed),
            VMO_ACCOUNTING_EVENT_FLAGS[index].load(Ordering::Relaxed)
        );
    }
}

