/// VMO Loading slot 的生命周期状态。
#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum VmoPageLoadState {
    /// 后端 pager I/O 或初始化仍在进行。
    Loading,
    /// 页帧已经成功发布，等待者可以重新读取 page cache。
    Completed,
    /// 后端 pager 返回错误，等待者按现有读语义重新提交或返回错误。
    Failed,
    /// resize、decommit 或 generation 失效撤销了本次加载。
    Cancelled,
}

impl VmoPageLoadState {
    const LOADING: usize = 0;
    const COMPLETED: usize = 1;
    const FAILED: usize = 2;
    const CANCELLED: usize = 3;

    /// 从原子整数恢复生命周期状态。
    fn from_usize(value: usize) -> Self {
        match value {
            Self::LOADING => Self::Loading,
            Self::COMPLETED => Self::Completed,
            Self::FAILED => Self::Failed,
            Self::CANCELLED => Self::Cancelled,
            _ => Self::Cancelled,
        }
    }

    /// 返回可写入原子状态槽的整数表示。
    fn as_usize(self) -> usize {
        match self {
            Self::Loading => Self::LOADING,
            Self::Completed => Self::COMPLETED,
            Self::Failed => Self::FAILED,
            Self::Cancelled => Self::CANCELLED,
        }
    }
}

