/// clone/fork 创建事务中可由 ktest 注入失败的位置。
#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub(crate) enum KtestCloneFailurePoint {
    /// 子地址空间已经完成 fork 或共享选择。
    AfterRootVmar,
    /// 进程式 clone 的 pending child 已经构造完成。
    AfterPendingChild,
    /// 进程 pid 或线程 tid 已经取得，但尚未进入公开关系。
    AfterChildTid,
    /// 子线程文件系统上下文已经派生，fd table owner 记录仍处于未发布状态。
    AfterFsContext,
    /// 子线程对象已经构造完成，但尚未登记到进程线程表。
    AfterThreadBuild,
    /// vfork 父等待器已经登记，子线程尚未提交调度器。
    AfterVforkArm,
    /// 发布临界区内即将把子线程登记到进程线程表。
    BeforePublishAttach,
    /// 子线程已经登记到进程线程表，尚未提交调度器。
    AfterPublishAttach,
}

impl KtestCloneFailurePoint {
    /// 返回 ktest failpoint 使用的非零编码。
    #[cfg(feature = "ktest")]
    const fn code(self) -> u8 {
        match self {
            Self::AfterRootVmar => 1,
            Self::AfterPendingChild => 2,
            Self::AfterChildTid => 3,
            Self::AfterFsContext => 4,
            Self::AfterThreadBuild => 5,
            Self::AfterVforkArm => 6,
            Self::BeforePublishAttach => 7,
            Self::AfterPublishAttach => 8,
        }
    }
}

#[cfg(feature = "ktest")]
static KTEST_CLONE_FAILURE_POINT: AtomicU8 = AtomicU8::new(0);

/// 设置下一次 clone/fork 创建事务命中的 ktest 失败点。
#[cfg(feature = "ktest")]
pub(crate) fn ktest_arm_clone_failure_point(point: KtestCloneFailurePoint) {
    KTEST_CLONE_FAILURE_POINT
        .compare_exchange(0, point.code(), Ordering::AcqRel, Ordering::Acquire)
        .expect("clone failure point is already armed");
}

/// 清除尚未消费的 clone/fork ktest 失败点。
#[cfg(feature = "ktest")]
pub(crate) fn ktest_clear_clone_failure_point() {
    KTEST_CLONE_FAILURE_POINT.store(0, Ordering::Release);
}

/// 在指定 clone/fork 创建位置执行一次性 ktest 失败注入。
pub(crate) fn ktest_inject_clone_failure(point: KtestCloneFailurePoint) -> Result<()> {
    #[cfg(feature = "ktest")]
    {
        if KTEST_CLONE_FAILURE_POINT
            .compare_exchange(point.code(), 0, Ordering::AcqRel, Ordering::Acquire)
            .is_ok()
        {
            return Err(Error::new(Errno::ENOMEM));
        }
    }

    let _ = point;
    Ok(())
}

