#[derive(Clone, Copy, PartialEq, Eq)]
enum RunnableRank {
    Normal,
    FifoOrRoundRobin(i32),
}

impl RunnableRank {
    /// 返回线程在当前单队列调度器中的可运行排序键。
    fn for_thread(thread: &Thread) -> Self {
        thread
            .fifo_rr_priority()
            .map(Self::FifoOrRoundRobin)
            .unwrap_or(Self::Normal)
    }

    /// 返回 `self` 是否应排在 `other` 前面。
    fn outranks(self, other: Self) -> bool {
        match (self, other) {
            (Self::FifoOrRoundRobin(left), Self::FifoOrRoundRobin(right)) => right < left,
            (Self::FifoOrRoundRobin(_), Self::Normal) => true,
            (Self::Normal, _) => false,
        }
    }
}

/// 保存可运行线程队列的调度器状态。
pub(super) struct Scheduler {
    runnable: VecDeque<Arc<Thread>>,
}

impl Scheduler {
    /// 创建空的全局 runnable 队列状态。
    pub(super) const fn new() -> Self {
        Self {
            runnable: VecDeque::new(),
        }
    }

    /// 取出当前 hart 上最应该运行的线程。
    fn pop_next_for(&mut self, hart_id: crate::hal::HartId) -> Option<Arc<Thread>> {
        let index = self.best_runnable_index_for(hart_id)?;
        self.runnable.remove(index)
    }

    /// 返回当前 hart 上最高优先级 runnable 的队列下标。
    fn best_runnable_index_for(&self, hart_id: crate::hal::HartId) -> Option<usize> {
        let mut best = None;

        for (index, thread) in self.runnable.iter().enumerate() {
            if !thread.can_run_on(hart_id) {
                continue;
            }

            let rank = RunnableRank::for_thread(thread.as_ref());
            match best {
                Some((_, best_rank)) if !rank.outranks(best_rank) => {}
                _ => {
                    best = Some((index, rank));
                    if matches!(rank, RunnableRank::FifoOrRoundRobin(MAX_FIFO_RR_PRIORITY)) {
                        break;
                    }
                }
            }
        }

        best.map(|(index, _)| index)
    }

    /// 返回当前 hart 上最高优先级 runnable 的排序键。
    fn best_runnable_rank_for(&self, hart_id: crate::hal::HartId) -> Option<RunnableRank> {
        self.best_runnable_index_for(hart_id)
            .map(|index| RunnableRank::for_thread(self.runnable[index].as_ref()))
    }

    /// 把一个 ready 线程追加到 runnable 队列尾部。
    fn push_runnable(&mut self, thread: Arc<Thread>) {
        self.runnable.push_back(thread);
    }
}

static SCHEDULER: SpinLock<Scheduler, LocalIrqDisabled> = SpinLock::new(Scheduler::new());

