/// 网络数据面一次阻塞等待的绝对截止时间。
#[derive(Clone, Copy)]
pub struct NetworkDeadline(Option<u64>);

impl NetworkDeadline {
    /// 构造没有有限超时约束的网络等待期限。
    pub const fn none() -> Self {
        Self(None)
    }

    /// 从 uptime 微秒绝对时间构造网络等待期限。
    pub const fn from_uptime_us(deadline_us: Option<u64>) -> Self {
        Self(deadline_us)
    }

    /// 计算下一轮网络轮询前最多可睡眠的微秒数。
    fn next_sleep_us(self) -> Result<u64> {
        match self.0 {
            Some(deadline) => {
                let now = crate::time::uptime_us();
                if deadline <= now {
                    Err(Error::new(Errno::EAGAIN))
                } else {
                    Ok((deadline - now).min(TCP_POLL_INTERVAL_US))
                }
            }
            None => Ok(TCP_POLL_INTERVAL_US),
        }
    }
}

/// 网络阻塞等待的可中断策略。
#[derive(Clone, Copy)]
struct NetworkWait {
    nonblocking: bool,
    deadline: NetworkDeadline,
}

impl NetworkWait {
    /// 构造一次网络 I/O 等待策略。
    fn new(nonblocking: bool, deadline: NetworkDeadline) -> Self {
        Self {
            nonblocking,
            deadline,
        }
    }

    /// 在进入睡眠前处理非阻塞、signal 与 deadline 边界。
    fn before_sleep(&self, check_interrupt: &mut impl FnMut() -> Result<()>) -> Result<u64> {
        if self.nonblocking {
            return Err(Error::new(Errno::EAGAIN));
        }
        check_interrupt()?;
        self.deadline.next_sleep_us()
    }

    /// 执行一轮网络阻塞等待，并在返回前再次检查可投递信号。
    fn sleep_one_round(&self, check_interrupt: &mut impl FnMut() -> Result<()>) -> Result<()> {
        let sleep_us = self.before_sleep(check_interrupt)?;
        crate::time::sleep_us(sleep_us);
        check_interrupt()
    }
}

/// 初始化内核网络栈。
///
/// 使用 QEMU user-net 的静态 IPv4 配置建立 smoltcp interface。
/// 该配置建立普通 IPv4 数据面，不包含远端 API 或域名特判。
pub fn init(cpu_affinity: HartMask) {
    let Some(device) = crate::drivers::virtio::net::global() else {
        log::info!("[net] virtio-net unavailable; smoltcp stack skipped");
        return;
    };

    let stack = Arc::new(NetStack::new(device));
    NET_STACK.call_once(|| stack.clone());
    stack.spawn_poller(cpu_affinity);
    log::info!(
        "[net] smoltcp stack initialized: ip={}/{} gateway={}",
        QEMU_USER_NET_IP,
        QEMU_USER_NET_PREFIX_LEN,
        QEMU_USER_NET_GATEWAY
    );
}

/// 通知网络栈 virtio-net 收到了外部中断。
///
/// 返回 `true` 表示中断已经交给网络 poller；返回 `false` 表示协议栈尚未初始化，
/// 驱动层需要自行丢弃并回收 RX buffer。
pub fn notify_device_irq() -> bool {
    let Some(stack) = NET_STACK.get() else {
        return false;
    };
    stack.notify_irq();
    true
}

/// 在调用线程上下文主动轮询一次网络栈。
pub fn poll_once() {
    if let Some(stack) = NET_STACK.get() {
        stack.poll_once();
    }
}

