pub(crate) fn init_thread() {
    log::info!("virtio-blk probe");
    log::debug!(
        "irq: local_enabled={} (enable before virtio I/O)",
        nexus::hal::irq::local_enabled()
    );
    nexus::hal::irq::enable_local();

    nexus::time::init();
    let runner_scene = config::runner_probe_scene();
    let runner_timeout_secs = config::runner_global_timeout_secs();
    nexus::runner_timeout::install_global_timeout(runner_timeout_secs);
    log::info!(
        "time: ticks_per_second={} tick_hz={} runner_timeout_secs={} debug_timeout_secs={}",
        nexus::hal::time::ticks_per_second(),
        nexus::hal::time::KERNEL_TICK_HZ,
        runner_timeout_secs,
        config::DEBUG_GLOBAL_TIMEOUT_SECS
    );
    nexus::time::enable_timer_interrupt_on_current_hart();

    nexus::drivers::virtio::blk::init_all();
    let root_dev = nexus::drivers::block::root_device();
    assert!(
        8 <= root_dev.metadata().nr_sectors,
        "root disk is too small"
    );
    let _net = nexus::drivers::virtio::net::init_optional();

    log::info!("ext4 mount root");
    let ext4 = Ext4Fs::mount_from(nexus::drivers::block::root_device())
        .unwrap_or_else(|err| panic!("mount root ext4 failed: {:?}", err));
    let vfs_fs: Arc<dyn FileSystem> = ext4;
    rootfs::init_root_mount(vfs_fs.clone());
    rootfs::mount_nexus_assets();
    log::info!("rootfs layout check (oscomp sdcard)");
    rootfs::prepare_oscomp_testsuits_root_layout();
    log::info!("rootfs layout check ok");

    let resolver = FsResolver::new();
    let boot_hart = nexus::cpu::boot_hart_id();

