//! RISC-V64 最早启动入口。

use crate::hal::{
    boot::PerApRawInfo,
    boot::__hal_rust_entry,
    imp::{
        arch::riscv64::boot_translation,
        config::{BOOT_STACK_SIZE, KERNEL_VMA_OFFSET, MAX_CPUS},
    },
};

extern "C" {
    static __cpu_local_start: u8;
}

const SATP_MODE_SV48: usize = 9 << 60;
const PER_AP_RAW_INFO_CPU_LOCAL_OFFSET: usize = core::mem::size_of::<usize>();
const PER_AP_RAW_INFO_SHIFT: usize = 4;

const _: [(); core::mem::size_of::<PerApRawInfo>()] = [(); 2 * core::mem::size_of::<usize>()];
const _: [(); core::mem::size_of::<PerApRawInfo>()] = [(); 1 << PER_AP_RAW_INFO_SHIFT];

#[used]
#[link_section = ".boot.data"]
static START_VIRT_ENTRY: unsafe extern "C" fn(usize, usize) -> ! = start_virt;

#[used]
#[link_section = ".boot.data"]
static HAL_RUST_ENTRY: unsafe extern "C" fn(usize, usize) -> ! = __hal_rust_entry;

/// RISC-V 最早入口。
///
/// # Safety
///
/// - 只能作为机器启动入口使用；
/// - 调用时 CPU 仍处于最早启动状态，尚未建立普通 Rust 调用环境。
#[export_name = "_start"]
#[naked]
#[link_section = ".boot.entry"]
unsafe extern "C" fn boot_start() -> ! {
    core::arch::naked_asm!(
        "mv      s0, a0",
        "mv      s1, a1",
        "li      t4, {max_cpus}",
        "bgeu    s0, t4, 2f",

        // AP 启动协议：
        // - a1 = PerApRawInfo 数组指针 | 1（最低位用作标记位）
        // - AP 不使用静态启动栈，也不负责初始化启动页表
        "andi    t0, s1, 1",
        "bnez    t0, 3f",

        // ---- BSP 路径：使用单份启动栈，并初始化启动页表 ----
        "la      sp, __hal_bsp_boot_stack",
        "li      t0, {stack_size}",
        "add     sp, sp, t0",
        "call    {init_boot_page_table}",
        "la      t0, {boot_l4pt}",
        "srli    t0, t0, 12",
        "li      t1, {satp_mode_sv48}",
        "or      t0, t0, t1",
        "csrw    satp, t0",
        "sfence.vma",
        "li      t4, {kernel_vma_offset}",
        "or      sp, sp, t4",
        "la      t0, {start_virt_entry}",
        // 从启动数据区取出高地址入口函数指针。
        "ld      t0, 0(t0)",
        "mv      a0, s0",
        "mv      a1, s1",
        // 跳转到寄存器中的地址，不保存返回地址。
        "jr      t0",

        // ---- AP 路径：启动页表已由 BSP 初始化；从 PerApRawInfo 取栈与 CPU 本地区 ----
        "3:",
        // 先保留带标记位的 `boot_arg`，用于传给 Rust 入口做 BSP/AP 分流。
        "mv      t3, s1",
        // 去掉 a1 低位标记，恢复启动参数数组指针。
        "andi    s1, s1, -2",
        "la      t0, {boot_l4pt}",
        "srli    t0, t0, 12",
        "li      t1, {satp_mode_sv48}",
        "or      t0, t0, t1",
        "csrw    satp, t0",
        "sfence.vma",

        // t2 = raw_base + hart_id * size_of(PerApRawInfo)
        // `mul` 需要 RISC-V M/Zmmul 扩展；这里用移位表达固定大小乘法。
        "slli    t1, s0, {per_ap_raw_info_shift}",
        "add     t2, s1, t1",
        // sp = raw[hart_id].stack_top
        "ld      sp, 0(t2)",
        // gp = raw[hart_id].cpu_local
        "ld      gp, {per_ap_raw_info_cpu_local_offset}(t2)",

        // 进入 Rust HAL 入口：
        // - a1 仍传入带标记位的 `boot_arg`
        // - dtb_pa 对 AP 无意义；`a1 & 1` 用于区分 BSP 与 AP，不能置 0
        "mv      a0, s0",
        "mv      a1, t3",
        "la      t0, {rust_entry_ptr}",
        "ld      t0, 0(t0)",
        "jr      t0",

        "2:",
        "wfi",
        "j       2b",
        max_cpus = const MAX_CPUS,
        stack_size = const BOOT_STACK_SIZE,
        satp_mode_sv48 = const SATP_MODE_SV48,
        kernel_vma_offset = const KERNEL_VMA_OFFSET,
        per_ap_raw_info_shift = const PER_AP_RAW_INFO_SHIFT,
        per_ap_raw_info_cpu_local_offset = const PER_AP_RAW_INFO_CPU_LOCAL_OFFSET,
        init_boot_page_table = sym boot_translation::init_boot_page_table,
        boot_l4pt = sym boot_translation::BOOT_L4PT,
        start_virt_entry = sym START_VIRT_ENTRY,
        rust_entry_ptr = sym HAL_RUST_ENTRY,
    );
}

#[link_section = ".text.hal.entry"]
unsafe extern "C" fn start_virt(hart_id: usize, dtb_pa: usize) -> ! {
    core::arch::asm!(
        // - BSP 会把 CPU-local base 固定设置为 `__cpu_local_start`；
        // - AP 会从 `PerApRawInfo.cpu_local` 安装 base（见 `_start` 的 AP 路径）。
        "la      gp, {cpu_local_start}",
        cpu_local_start = sym __cpu_local_start,
        options(nostack),
    );

    unsafe { __hal_rust_entry(hart_id, dtb_pa) }
}

#![no_std]
#![no_main]

use core::arch::asm;

#[panic_handler]
fn panic(_: &core::panic::PanicInfo) -> ! {
    sys_exit(1)
}

static mut INIT_DATA: u64 = 0x1122_3344_5566_7788;
static mut INIT_BSS: [u8; 8192] = [0; 8192];

#[no_mangle]
#[link_section = ".text.entry"]
extern "C" fn _start() -> ! {
    // SAFETY: 该测试程序单线程执行，静态可变数据只在入口内顺序访问，
    // 用于主动触发用户映射的读写 fault，不与其它执行流共享。
    unsafe {
        // 触发由文件内容提供的私有映射读缺页和写缺页。
        let before = INIT_DATA;
        INIT_DATA = before.wrapping_add(1);

        // 触发匿名 BSS 映射缺页，跨页写入确保至少发生一次缺页。
        INIT_BSS[0] = 0x5a;
        INIT_BSS[4096] = 0xa5;
        core::hint::black_box(INIT_BSS[0]);
        core::hint::black_box(INIT_BSS[4096]);
    }

    sys_exit(0)
}

#[inline(always)]
/// 通过 `exit` syscall 结束当前用户程序。
fn sys_exit(code: usize) -> ! {
    const SYS_EXIT: usize = 93;

    #[cfg(target_arch = "riscv64")]
    // SAFETY: 按 RISC-V 用户态 syscall ABI 填充退出号与退出码；
    // `options(noreturn)` 与 `exit` 语义一致，不会返回到调用点。
    unsafe {
        asm!(
            "ecall",
            in("a0") code,
            in("a7") SYS_EXIT,
            options(noreturn)
        )
    }

    #[cfg(target_arch = "loongarch64")]
    // SAFETY: 按 LoongArch64 用户态 syscall ABI 填充退出号与退出码；
    // `options(noreturn)` 与 `exit` 语义一致，不会返回到调用点。
    unsafe {
        asm!(
            "syscall 0",
            in("$a0") code,
            in("$a7") SYS_EXIT,
            options(noreturn)
        )
    }
}

//! RCU（Read-Copy Update）。
//!
//! `RcuDrop` 与宽限期监控器用于支撑页表游离子树回收，避免并发读者看到已经复用的页表页。

use alloc::{boxed::Box, collections::VecDeque};
use core::{
    mem::ManuallyDrop,
    ops::Deref,
    sync::atomic::{AtomicBool, Ordering},
};

use crate::sync::SpinLock;

use crate::{cpu, cpu::PinCurrentHart, sync::Once, thread::atomic_mode::AsAtomicModeGuard};

type Callback = Box<dyn FnOnce() + Send + 'static>;
type Callbacks = VecDeque<Callback>;

struct RcuMonitor {
    is_monitoring: AtomicBool,
    full_mask_bits: u64,
    state: SpinLock<State>,
}

impl RcuMonitor {
    fn new() -> Self {
        Self {
            is_monitoring: AtomicBool::new(false),
            full_mask_bits: cpu::possible_harts().bits(),
            state: SpinLock::new(State::new()),
        }
    }

    fn after_grace_period(&self, f: Callback) {
        let mut state = self.state.disable_irq().lock();

        state.next_callbacks.push_back(f);

        if !state.current_gp.is_complete() {
            return;
        }

        let callbacks = core::mem::take(&mut state.next_callbacks);
        state.current_gp.restart(callbacks);
        self.is_monitoring.store(true, Ordering::Relaxed);
    }

    unsafe fn finish_grace_period(&self) {
        if !self.is_monitoring.load(Ordering::Relaxed) {
            return;
        }

        let callbacks = {
            let mut state = self.state.disable_irq().lock();

            if state.current_gp.is_complete() {
                return;
            }

            let this_cpu = state.as_atomic_mode_guard().current_hart();
            state
                .current_gp
                .observe_quiescent_state(this_cpu, self.full_mask_bits);

            if !state.current_gp.is_complete() {
                return;
            }

            let current_callbacks = state.current_gp.take_callbacks();

            if !state.next_callbacks.is_empty() {
                let callbacks = core::mem::take(&mut state.next_callbacks);
                state.current_gp.restart(callbacks);
            } else {
                self.is_monitoring.store(false, Ordering::Relaxed);
            }

            current_callbacks
        };

        for f in callbacks {
            crate::mm::heap::check_slab256_dealloc_watch("rcu:finish_grace_period:before_callback");
            (f)();
            crate::mm::heap::check_slab256_dealloc_watch("rcu:finish_grace_period:after_callback");
        }
    }
}

struct State {
    current_gp: GracePeriod,
    next_callbacks: Callbacks,
}

impl State {
    fn new() -> Self {
        Self {
            current_gp: GracePeriod::new(),
            next_callbacks: VecDeque::new(),
        }
    }
}

struct GracePeriod {
    callbacks: Callbacks,
    seen_mask_bits: u64,
    is_complete: bool,
}

impl GracePeriod {
    fn new() -> Self {
        Self {
            callbacks: VecDeque::new(),
            seen_mask_bits: 0,
            is_complete: true,
        }
    }

    fn is_complete(&self) -> bool {
        self.is_complete
    }

    fn observe_quiescent_state(&mut self, cpu_id: crate::hal::HartId, full_mask_bits: u64) {
        self.seen_mask_bits |= crate::hal::HartMask::empty().insert(cpu_id).bits();
        if (self.seen_mask_bits & full_mask_bits) == full_mask_bits {
            self.is_complete = true;
        }
    }

    fn take_callbacks(&mut self) -> Callbacks {
        core::mem::take(&mut self.callbacks)
    }

    fn restart(&mut self, callbacks: Callbacks) {
        self.is_complete = false;
        self.seen_mask_bits = 0;
        self.callbacks = callbacks;
    }
}

static RCU_MONITOR: Once<RcuMonitor> = Once::new();

/// RCU 宽限期推进结果。
#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum GracePeriodAdvance {
    /// 当前调用点满足推进条件，并调用了一次宽限期推进入口。
    Advanced,
    /// 当前调用点不能安全推进宽限期。
    Skipped,
}

/// 初始化 RCU 监控器。
///
/// # Panics
///
/// 若在启动 CPU 未完成 `cpu::init_on_bsp()` 之前调用，可能因 `possible_harts()` 未初始化而 panic。
pub fn init() {
    RCU_MONITOR.call_once(RcuMonitor::new);
}

fn monitor() -> &'static RcuMonitor {
    RCU_MONITOR.get().expect("rcu monitor is not initialized")
}

/// 在当前 RCU 宽限期结束后执行回调。
pub fn after_grace_period(f: impl FnOnce() + Send + 'static) {
    monitor().after_grace_period(Box::new(f));
}

/// 标记当前 CPU 经过一次静止状态，并在满足条件时推进 RCU 宽限期。
///
/// # Safety
///
/// 调用者必须保证当前 CPU 不处于 RCU 读侧临界区，也不处于不可调度窗口。
pub unsafe fn finish_grace_period() {
    // SAFETY: 安全性由调用者承担。
    unsafe { monitor().finish_grace_period() };
}

/// 在分配器 slowpath 中尝试推进一次 RCU 宽限期。
///
/// 该入口只在 RCU 已初始化、当前执行点可调度且本地 IRQ 开启时执行推进；
/// 不满足条件时直接返回跳过，让调用方继续原有回收或错误传播路径。
pub fn try_finish_grace_period_for_allocator() -> GracePeriodAdvance {
    let Some(monitor) = RCU_MONITOR.get() else {
        return GracePeriodAdvance::Skipped;
    };
    if crate::thread::atomic_mode::IN_BOOTSTRAP_CONTEXT.load(Ordering::Relaxed) {
        return GracePeriodAdvance::Skipped;
    }
    if !crate::thread::atomic_mode::can_sleep() || !crate::hal::irq::local_enabled() {
        return GracePeriodAdvance::Skipped;
    }

    // SAFETY:
    // - bootstrap、`can_sleep()` 与 IRQ 开启检查排除了抢占关闭和 IRQ 关闭窗口；
    // - 页表 cursor 与类型化自旋锁都会进入不可调度或关中断窗口；
    // - allocator slowpath 在全局页帧分配器锁外调用本入口；
    // - 本入口不阻塞等待宽限期，只上报当前 CPU 的一次静止状态。
    unsafe {
        monitor.finish_grace_period();
    }
    GracePeriodAdvance::Advanced
}

/// 在 RCU 宽限期之后再释放内部对象的包装器。
#[derive(Clone, Debug, Default, PartialEq, Eq, PartialOrd, Ord, Hash)]
#[repr(transparent)]
pub struct RcuDrop<T: Send + 'static> {
    value: ManuallyDrop<T>,
}

impl<T: Send + 'static> RcuDrop<T> {
    /// 创建一个新的延迟释放包装器。
    pub fn new(value: T) -> Self {
        Self {
            value: ManuallyDrop::new(value),
        }
    }
}

impl<T: Send + 'static> Deref for RcuDrop<T> {
    type Target = T;

    fn deref(&self) -> &Self::Target {
        &self.value
    }
}

impl<T: Send + 'static> Drop for RcuDrop<T> {
    fn drop(&mut self) {
        // SAFETY: `ManuallyDrop` 在 take 后不再使用。
        let taken = unsafe { ManuallyDrop::take(&mut self.value) };
        after_grace_period(move || drop(taken));
    }
}

//! `SpinLock<T, G>`：带类型化保护策略的自旋锁。

use core::{
    fmt,
    marker::PhantomData,
    ops::{Deref, DerefMut},
};

use spin::{Mutex, MutexGuard};

use super::guard::{LocalIrqDisabled, PreemptDisabled, SpinGuardian};
use crate::thread::atomic_mode::AsAtomicModeGuard;

/// 自旋锁。
///
/// `G` 指定持锁期间的执行环境：
/// - `PreemptDisabled`：禁抢占；
/// - `LocalIrqDisabled`：关本地中断。
#[repr(transparent)]
pub struct SpinLock<T: ?Sized, G = PreemptDisabled> {
    phantom: PhantomData<G>,
    inner: Mutex<T>,
}

impl<T, G> SpinLock<T, G> {
    /// 创建一个新的自旋锁。
    pub const fn new(val: T) -> Self {
        Self {
            phantom: PhantomData,
            inner: Mutex::new(val),
        }
    }
}

impl<T: ?Sized> SpinLock<T, PreemptDisabled> {
    /// 将“禁抢占”守护升级为“关本地中断”守护。
    pub fn disable_irq(&self) -> &SpinLock<T, LocalIrqDisabled> {
        let ptr = self as *const SpinLock<T, PreemptDisabled>;
        let ptr = ptr as *const SpinLock<T, LocalIrqDisabled>;
        // SAFETY: `SpinLock<T, _>` 由 `#[repr(transparent)]` 保证相同布局，且 `G` 仅影响语义。
        unsafe { &*ptr }
    }
}

impl<T: ?Sized, G: SpinGuardian> SpinLock<T, G> {
    /// 获取锁，并在持锁期间进入不可调度窗口。
    pub fn lock(&self) -> SpinLockGuard<'_, T, G> {
        let guard = G::guard();
        let lock_guard = loop {
            if let Some(lock_guard) = self.inner.try_lock() {
                break lock_guard;
            }
            crate::runner_timeout::record_spin_contention(core::any::type_name::<T>());
            crate::hal::cpu::relax();
        };
        SpinLockGuard { lock_guard, guard }
    }

    /// 尝试获取锁。
    pub fn try_lock(&self) -> Option<SpinLockGuard<'_, T, G>> {
        let guard = G::guard();
        let lock_guard = self.inner.try_lock()?;
        Some(SpinLockGuard { lock_guard, guard })
    }

    /// 返回底层数据的可变引用（零开销）。
    pub fn get_mut(&mut self) -> &mut T {
        self.inner.get_mut()
    }
}

impl<T: ?Sized + fmt::Debug, G> fmt::Debug for SpinLock<T, G> {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        fmt::Debug::fmt(&self.inner, f)
    }
}

unsafe impl<T: ?Sized + Send, G> Send for SpinLock<T, G> {}
unsafe impl<T: ?Sized + Send, G> Sync for SpinLock<T, G> {}

/// 自旋锁保护对象。
#[clippy::has_significant_drop]
#[must_use]
pub struct SpinLockGuard<'a, T: ?Sized, G: SpinGuardian> {
    // 释放顺序必须先解锁，再恢复本地中断或抢占状态。
    lock_guard: MutexGuard<'a, T>,
    guard: G::Guard,
}

impl<T: ?Sized, G: SpinGuardian> AsAtomicModeGuard for SpinLockGuard<'_, T, G> {
    fn as_atomic_mode_guard(&self) -> &dyn crate::thread::atomic_mode::InAtomicMode {
        self.guard.as_atomic_mode_guard()
    }
}

impl<T: ?Sized, G: SpinGuardian> Deref for SpinLockGuard<'_, T, G> {
    type Target = T;

    fn deref(&self) -> &Self::Target {
        &self.lock_guard
    }
}

impl<T: ?Sized, G: SpinGuardian> DerefMut for SpinLockGuard<'_, T, G> {
    fn deref_mut(&mut self) -> &mut Self::Target {
        &mut self.lock_guard
    }
}

impl<T: ?Sized + fmt::Debug, G: SpinGuardian> fmt::Debug for SpinLockGuard<'_, T, G> {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        fmt::Debug::fmt(&**self, f)
    }
}

impl<T: ?Sized, G: SpinGuardian> !Send for SpinLockGuard<'_, T, G> {}

