/// 返回全局启动信息。
pub fn boot_info() -> &'static BootInfo {
    BOOT_INFO.get().expect("BootInfo is not ready")
}

/// HAL 启动入口（由架构 `_start` 调用）。
///
/// - 启动 CPU：清零 `.bss`、构造启动信息、完成早期初始化并跳入内核入口；
/// - 其他 CPU：完成本地初始化后跳入内核提供的其他 CPU 入口。
///
/// 第二参数的最低位用于区分启动 CPU 和其他 CPU：
/// - `boot_arg & 1 == 1` 表示其他 CPU，剩余位是 `PerApRawInfo` 数组指针；
/// - `boot_arg & 1 == 0` 表示启动 CPU，此时 RISC-V 传入 DTB 物理地址，LoongArch64 传入 0。
///
/// # Safety
/// - 必须只由启动汇编入口调用，CPU 已处于期望的特权态、关中断状态且栈已就绪；
/// - hart id 和第二参数必须遵守启动协议。
#[no_mangle]
pub(crate) unsafe extern "C" fn __hal_rust_entry(hart_id: usize, boot_arg: usize) -> ! {
    let is_ap = (boot_arg & 1) != 0;
    if !is_ap {
        // 启动 CPU 在进入内核入口前完成 `.bss` 清零。
        //
        // SAFETY: `__hal_rust_entry` 只由最早启动入口调用；
        // 其他 CPU 只会在启动 CPU 准备好启动参数后才开始执行内核镜像代码。
        unsafe { bss::clear_bss() };

        // 安装 trap 向量，避免开中断后缺少入口。
        crate::hal::cpu::early_init();
        crate::hal::trap::early_init();

        BOOT_INFO.call_once(|| {
            // SAFETY: 启动 CPU 路径下第二参数来自启动协议：
            // RISC-V 传入 DTB 物理地址，LoongArch64 传入 0；平台探测前提在本入口统一建立。
            unsafe { crate::hal::imp::platform::probe_boot_info(hart_id, boot_arg) }
        });

        crate::hal::console::init_from_boot();
        primary_main()
    } else {
        // 安装 trap 向量，避免开中断后缺少入口。
        crate::hal::cpu::early_init();
        crate::hal::trap::early_init();

        // SAFETY:
        // - 启动 CPU 会在启动其他 CPU 之前完成 `cpu::init_on_bsp()`；
        // - 早期汇编路径已安装好当前 CPU 的本地区基址；
        // - 当前 hart id 与实际执行 CPU 一致。
        unsafe { crate::cpu::init_on_ap(HartId::new(hart_id)) };

        secondary_main(hart_id)
    }
}

fn primary_main() -> ! {
    extern "Rust" {
        fn __hal_kernel_main(boot: &'static BootInfo) -> !;
    }
    // SAFETY: `__hal_kernel_main` 由最终链接的内核提供，签名/ABI 与声明一致；

