pub struct HartId(u16);

impl HartId {
    /// 从启动协议给出的 hart id 构造。
    #[inline]
    pub const fn new(hart_id: usize) -> Self {
        Self(hart_id as u16)
    }

    /// 转为 `usize`，用于数组索引和编号比较。
    #[inline]
    pub const fn as_usize(self) -> usize {
        self.0 as usize
    }
}

/// 将越界整数转换成 `HartId` 的错误。
#[derive(Clone, Copy, Debug)]
pub struct HartIdFromIntError;

impl TryFrom<usize> for HartId {
    type Error = HartIdFromIntError;

    fn try_from(value: usize) -> Result<Self, Self::Error> {
        if value < crate::hal::MAX_CPUS {
            Ok(Self(value as u16))
        } else {
            Err(HartIdFromIntError)
        }
    }
