/// hart 集合。
///
/// 第 i 位表示 hart id 为 i。
#[repr(transparent)]
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct HartMask(u64);

impl HartMask {
    /// 空集合。
    #[inline]
    pub const fn empty() -> Self {
        Self(0)
    }

    /// 从原始位图构造。
    #[inline]
    pub const fn from_bits(bits: u64) -> Self {
        Self(bits)
    }

    /// 原始位图。
    #[inline]
    pub const fn bits(self) -> u64 {
        self.0
    }

    #[inline]
    const fn hart_bit(hart_id: HartId) -> u64 {
        let shift = hart_id.0 as u32;
        if shift >= u64::BITS {
            0
        } else {
            1u64 << shift
        }
    }

    /// 判断集合中是否包含指定 hart。
    #[inline]
    pub const fn contains(self, hart_id: HartId) -> bool {
        (self.0 & Self::hart_bit(hart_id)) != 0
    }

    /// 返回插入 hart 后的新集合。
    #[inline]
    pub const fn insert(self, hart_id: HartId) -> Self {
        Self(self.0 | Self::hart_bit(hart_id))
    }

    /// 返回移除 hart 后的新集合。
    #[inline]
    pub const fn remove(self, hart_id: HartId) -> Self {
        Self(self.0 & !Self::hart_bit(hart_id))
    }

    /// 迭代集合中的 hart，顺序按编号递增。
    #[inline]
    pub fn iter(self) -> impl Iterator<Item = HartId> {
        HartMaskIter { bits: self.0 }
    }
}

/// `HartMask` 的迭代器，按位从低到高返回 hart。
#[derive(Clone, Debug)]
struct HartMaskIter {
    bits: u64,
}

impl Iterator for HartMaskIter {
    type Item = HartId;

    #[inline]
    fn next(&mut self) -> Option<Self::Item> {
        if self.bits == 0 {
            return None;
        }
        let tz = self.bits.trailing_zeros() as u16;
        self.bits &= self.bits - 1;
        Some(HartId(tz))
    }
}

