bitflags! {
    /// VMAR 映射权限（READ/WRITE/EXEC）。
    #[derive(Clone, Copy, Debug, PartialEq, Eq)]
    pub struct VmPerms: u8 {
        /// 可读。
        const READ  = 0b001;
        /// 可写。
        const WRITE = 0b010;
        /// 可执行。
        const EXEC  = 0b100;
    }
}

impl From<VmPerms> for PageFlags {
    /// 将 VMAR 语义权限转换为可安装到页表的硬件权限位。
    ///
    /// RISC-V 不接受 W-only 叶子 PTE；部分架构也允许把 `PROT_WRITE` 表达为
    /// 硬件可读写页。VMAR 的语义权限仍记录在 `VmMarker`，这里仅保证落表权限可前进。
    fn from(perms: VmPerms) -> PageFlags {
        let mut flags = PageFlags::empty();
        if perms.contains(VmPerms::READ) || perms.contains(VmPerms::WRITE) {
            flags |= PageFlags::R;
        }
        if perms.contains(VmPerms::WRITE) {
            flags |= PageFlags::W;
        }
        if perms.contains(VmPerms::EXEC) {
            flags |= PageFlags::X;
        }
        flags
    }
}

impl From<PageFlags> for VmPerms {
    fn from(flags: PageFlags) -> VmPerms {
        let mut perms = VmPerms::empty();
        if flags.contains(PageFlags::R) {
            perms |= VmPerms::READ;
        }
        if flags.contains(PageFlags::W) {
            perms |= VmPerms::WRITE;
        }
        if flags.contains(PageFlags::X) {
            perms |= VmPerms::EXEC;
        }
        perms
    }
}

