}

/// 打印当前 CPU 上与堆坏空闲节点相关的线程上下文线索。
pub(super) fn log_heap_corruption_thread_context(
    stage: &'static str,
    previous_slot: usize,
    bad_node: usize,
) {
    let hart = crate::cpu::current_hart_racy().as_usize();
    let live_sp = current_stack_pointer();
    let current_thread_ptr = CURRENT_THREAD_PTR.load();
    let previous_thread_ptr = PREVIOUS_THREAD_PTR.load();
    log::error!(
        "[thread] heap corruption context stage={} hart={} live_sp={:#x} current={:#x} previous={:#x} previous_slot={:#x} bad_node={:#x}",
        stage,
        hart,
        live_sp,
        current_thread_ptr as usize,
        previous_thread_ptr as usize,
        previous_slot,
        bad_node
    );
    log_thread_context("current", current_thread_ptr, previous_slot, bad_node);
    log_thread_context("previous", previous_thread_ptr, previous_slot, bad_node);
}

/// 切换到目标线程。
///
/// - 安装当前线程和先前线程状态；
/// - 从当前线程或启动上下文切走；
/// - 重新切回本调用点时完成先前线程的延迟处理。
#[track_caller]
pub(super) fn switch_to_thread(next_thread: Arc<Thread>) {
    super::atomic_mode::might_sleep();
    // SAFETY: `might_sleep()` 已经保证当前不处于不可调度窗口，因此可以推进 RCU 宽限期。
    unsafe {
        crate::sync::rcu::finish_grace_period();
    }
    let irq_guard = crate::cpu::disable_local_irq();

    let current_thread_ptr = CURRENT_THREAD_PTR.load();
    let current_ctx_ptr = if current_thread_ptr.is_null() {
        bootstrap_context_ptr()
    } else {
        // SAFETY: `CURRENT_THREAD_PTR` 只由处理器切换路径更新；
        // 非空时必然指向当前 CPU 上正在运行的 `Thread`。
        unsafe { (*current_thread_ptr).context_mut_ptr() }
    };

    before_switching_to(current_thread_ptr, &next_thread);

    let next_ctx_ptr = next_thread.context_ptr();
    CURRENT_THREAD_PTR.store(Arc::into_raw(next_thread));
    assert!(
        PREVIOUS_THREAD_PTR.load().is_null(),
        "previous thread slot must be empty before switching"
    );
    PREVIOUS_THREAD_PTR.store(current_thread_ptr);

    // 汇编切换窗口必须保持本地中断关闭；保护对象不能在旧上下文释放，
    // 本地中断会在新上下文完成线程状态交接后直接开启。
    core::mem::forget(irq_guard);

    // SAFETY:
    // - `current_ctx_ptr` 指向当前上下文的可写位置；
    // - `next_ctx_ptr` 指向目标线程已经初始化好的上下文；
    // - 两者生命周期均由当前切换协议保证。
    unsafe { context_switch(next_ctx_ptr, current_ctx_ptr) };

