/// VFS dentry。
pub(super) struct Dentry {
    inode: Arc<dyn Inode>,
    type_: InodeType,
    name_and_parent: RwLock<Option<(String, Arc<Dentry>)>>,
    children: RwLock<DentryChildren>,
    mount_count: AtomicU32,
    linked: AtomicBool,
    this: alloc::sync::Weak<Dentry>,
}

impl Dentry {
    /// 构造没有父目录项的根目录项。
    pub(super) fn new_root(inode: Arc<dyn Inode>) -> Arc<Self> {
        Arc::new_cyclic(|weak_self| Self {
            type_: inode.type_(),
            inode,
            name_and_parent: RwLock::new(None),
            children: RwLock::new(DentryChildren::new()),
            mount_count: AtomicU32::new(0),
            linked: AtomicBool::new(true),
            this: weak_self.clone(),
        })
    }

    /// 构造一个已挂入父目录的普通 dentry。
    fn new_leaf(inode: Arc<dyn Inode>, name: &str, parent: Arc<Dentry>) -> Arc<Self> {
        Arc::new_cyclic(|weak_self| Self {
            type_: inode.type_(),
            inode,
            name_and_parent: RwLock::new(Some((String::from(name), parent))),
            children: RwLock::new(DentryChildren::new()),
            mount_count: AtomicU32::new(0),
            linked: AtomicBool::new(true),
            this: weak_self.clone(),
        })
    }

    pub(super) fn type_(&self) -> InodeType {
        self.type_
    }

    pub(super) fn inode(&self) -> &Arc<dyn Inode> {
        &self.inode
    }

    pub(super) fn name(&self) -> String {
        self.name_and_parent
            .read()
            .as_ref()
            .map(|(name, _)| name.clone())
            .unwrap_or_else(|| String::from("/"))
    }

    pub(super) fn parent(&self) -> Option<Arc<Self>> {
        self.name_and_parent
            .read()
            .as_ref()
            .map(|(_, parent)| parent.clone())

