    init_realtime_source();
    init_coarse_realtime_base();
}

/// 注册一个 timer tick 超时回调。
///
/// 回调在 timer 中断上下文执行，参数是已经递增后的全局 tick。调用方只能在回调里做
/// 原子读写、短小诊断和终止动作，不能分配内存、阻塞或依赖调度器运行。
pub fn register_tick_timeout(handler: fn(u64)) {
    let _ = TICK_TIMEOUT.call_once(|| handler);
}

/// 在当前 hart 上启用周期 timer 中断。
///
/// 调用方需要先开启本地中断，否则计时器中断不会被处理。
pub fn enable_timer_interrupt_on_current_hart() {
    crate::hal::time::enable_timer_interrupt();
}

/// 返回自启用计时以来的时钟节拍数。
pub fn ticks() -> u64 {
    TICKS.load(Ordering::Relaxed)
}

/// 返回粗粒度时钟的纳秒分辨率。
pub fn coarse_resolution_ns() -> u64 {
    1_000_000_000u64.div_ceil(crate::hal::time::KERNEL_TICK_HZ)
}

/// 将硬件单调计数器转换为单调递增的微秒数。
pub fn uptime_us() -> u64 {
    monotonic_ticks_to_us(crate::hal::time::monotonic_ticks())
}

/// 返回按内核 tick 粒度更新的单调微秒时间。
pub fn coarse_uptime_us() -> u64 {
    coarse_ticks_to_us(ticks())
}

/// 返回硬件单调计数器对应的纳秒级分辨率。
pub fn monotonic_resolution_ns() -> u64 {
    1_000u64.max(1_000_000_000u64.div_ceil(crate::hal::time::ticks_per_second()))
}

/// 按平台时基频率把硬件 tick 换算为微秒。
fn monotonic_ticks_to_us(ticks: u64) -> u64 {
    let ticks_per_second = crate::hal::time::ticks_per_second();
    if ticks_per_second % MICROS_PER_SEC == 0 {
        return ticks / (ticks_per_second / MICROS_PER_SEC);
    }
    if MICROS_PER_SEC % ticks_per_second == 0 {
        return ticks.saturating_mul(MICROS_PER_SEC / ticks_per_second);
    }

