const RSEQ_FLAG_UNREGISTER: u32 = 1 << 0;
const RSEQ_FLAG_SLICE_EXT_DEFAULT_ON: u32 = 1 << 1;
const ORIG_RSEQ_SIZE: u32 = 32;
const RSEQ_ALLOC_ALIGN: usize = 64;
const RSEQ_CS_ALIGN: usize = 32;
const RSEQ_CS_SIZE: usize = 32;

const RSEQ_CPU_ID_UNINITIALIZED: u32 = u32::MAX;

const RSEQ_CPU_ID_START_OFFSET: usize = 0;
const RSEQ_CPU_ID_OFFSET: usize = 4;
const RSEQ_CS_OFFSET: usize = 8;
const RSEQ_FLAGS_OFFSET: usize = 16;
const RSEQ_NODE_ID_OFFSET: usize = 20;
const RSEQ_MM_CID_OFFSET: usize = 24;
const RSEQ_SLICE_CTRL_OFFSET: usize = 28;
const RSEQ_END_OFFSET: u32 = 33;

const RSEQ_CS_START_IP_OFFSET: usize = 8;
const RSEQ_CS_POST_COMMIT_OFFSET_OFFSET: usize = 16;
const RSEQ_CS_ABORT_IP_OFFSET: usize = 24;

/// `rseq(2)` 的参数快照。
#[derive(Clone, Copy, Debug)]
struct RseqArgs {
    ptr: usize,
    len: u32,
    flags: u32,
    sig: u32,
}

impl RseqArgs {
    /// 从 syscall 参数寄存器解码 `rseq(rseq, len, flags, sig)`。
    fn decode(args: SyscallArgs) -> Result<Self> {
        Ok(Self {
            ptr: args.raw(0),
            len: args::arg_u32(args.raw(1))?,
            flags: args::arg_u32(args.raw(2))?,
            sig: args::arg_u32(args.raw(3))?,
        })
    }

    /// 判断本次调用是否注销本线程 rseq 注册区。
    const fn unregisters(self) -> bool {
        self.flags & RSEQ_FLAG_UNREGISTER != 0
    }

    /// 转换成线程本地保存的 rseq 注册快照。
    const fn registration(self) -> RseqRegistration {
        RseqRegistration::new(self.ptr, self.len, self.sig)
    }
}

/// 用户态 `struct rseq_cs` 中描述 critical section 的字段。
#[derive(Clone, Copy, Debug)]
struct RseqCriticalSection {
    start_ip: u64,
    post_commit_offset: u64,
    abort_ip: u64,
}

impl RseqCriticalSection {
    /// 判断给定用户 IP 是否仍处于可回滚的 critical section 区间内。
    fn contains_ip(self, ip: usize) -> bool {
        let Ok(ip) = u64::try_from(ip) else {
            return false;
        };
        ip.wrapping_sub(self.start_ip) < self.post_commit_offset
    }

    /// 返回 abort 入口地址的用户态指针。
    fn abort_ip(self) -> Result<usize> {
        usize::try_from(self.abort_ip).map_err(|_| Error::new(Errno::EINVAL))
    }
}

/// `rseq(2)`：为调用线程注册或注销 restartable sequence TLS 区域。
pub(super) fn sys_rseq(ctx: &SyscallContext, args: SyscallArgs) -> SyscallControlFlow {
    SyscallControlFlow::Continue(RseqArgs::decode(args).and_then(|args| do_rseq(ctx, args)))
}

/// 返回用户态前刷新本线程注册的 rseq 用户区。
pub(crate) fn update_current_thread_before_user_return(user_mode: &mut UserMode) -> Result<()> {
    let Some(current) = crate::thread::Thread::current() else {
        return Ok(());
    };
    let Some(registration) = current.thread_local().rseq_registration() else {
        return Ok(());
    };
    let Some(root_vmar) = current.user_root_vmar() else {
        return Ok(());
    };

    update_rseq_user_area(root_vmar.vm_space().as_ref(), registration)?;
    abort_active_critical_section(root_vmar.vm_space().as_ref(), registration, user_mode)
}

/// 按 `rseq(2)` 参数执行注册或注销。
fn do_rseq(ctx: &SyscallContext, args: RseqArgs) -> Result<isize> {
    if args.unregisters() {
        return unregister_rseq(ctx, args);
    }

    validate_registration_args(args)?;
    validate_current_thread_can_register_rseq(ctx, args.registration())?;
    reset_rseq_user_area(ctx.vm_space(), args.registration())?;
    register_current_thread_rseq(ctx, args.registration())?;
    update_rseq_user_area(ctx.vm_space(), args.registration())?;
    ret::ret_usize(0)
}

/// 注销调用线程已经注册的 rseq 区域。
fn unregister_rseq(ctx: &SyscallContext, args: RseqArgs) -> Result<isize> {
    if args.flags & !RSEQ_FLAG_UNREGISTER != 0 {
        return Err(Error::new(Errno::EINVAL));
    }
    validate_current_thread_can_unregister_rseq(ctx, args.registration())?;
    reset_rseq_ids(ctx.vm_space(), args.registration())?;
    unregister_current_thread_rseq(ctx, args.registration())?;
    ret::ret_usize(0)
}

/// 校验 rseq 注册请求中的 flags、用户区长度和对齐。
fn validate_registration_args(args: RseqArgs) -> Result<()> {
    if args.flags & !RSEQ_FLAG_SLICE_EXT_DEFAULT_ON != 0 {
        return Err(Error::new(Errno::EINVAL));
    }
    validate_rseq_region(args.ptr, args.len)
}

/// 校验用户态 rseq 区域覆盖本文件会写入的 ABI 字段。
fn validate_rseq_region(ptr: usize, len: u32) -> Result<()> {
    if len < ORIG_RSEQ_SIZE {
        return Err(Error::new(Errno::EINVAL));
    }

    let align = if len == ORIG_RSEQ_SIZE {
        ORIG_RSEQ_SIZE as usize
    } else {
        if len < RSEQ_END_OFFSET {
            return Err(Error::new(Errno::EINVAL));
        }
        RSEQ_ALLOC_ALIGN
    };

    validate_user_region(ptr, len as usize, align)
}

/// 校验一段用户内存位于用户空间且满足对齐约束。
fn validate_user_region(ptr: usize, len: usize, align: usize) -> Result<()> {
    if ptr % align != 0 {
        return Err(Error::new(Errno::EINVAL));
    }
    ptr.checked_add(len)
        .filter(|&end| end <= MAX_USERSPACE_VADDR)
        .ok_or_else(|| Error::new(Errno::EFAULT))?;
    Ok(())
}

/// 校验本线程状态允许安装给定 rseq 注册区。
fn validate_current_thread_can_register_rseq(
    ctx: &SyscallContext,
    registration: RseqRegistration,
) -> Result<()> {
    let Some(existing) = ctx.current().thread_local().rseq_registration() else {
        return Ok(());
    };
    if existing.user_ptr() != registration.user_ptr() || existing.len() != registration.len() {
        return Err(Error::new(Errno::EINVAL));
    }
    if existing.sig() != registration.sig() {
        return Err(Error::new(Errno::EPERM));
    }
    Err(Error::new(Errno::EBUSY))
}

/// 校验本线程状态允许注销给定 rseq 注册区。
fn validate_current_thread_can_unregister_rseq(
    ctx: &SyscallContext,
    registration: RseqRegistration,
) -> Result<()> {
    let Some(existing) = ctx.current().thread_local().rseq_registration() else {
        return Err(Error::new(Errno::EINVAL));
    };
    if existing.user_ptr() != registration.user_ptr() || existing.len() != registration.len() {
        return Err(Error::new(Errno::EINVAL));
    }
    if existing.sig() != registration.sig() {
        return Err(Error::new(Errno::EPERM));
    }
    Ok(())
}

/// 把 rseq 注册区安装到本线程本地状态。
fn register_current_thread_rseq(
    ctx: &SyscallContext,
    registration: RseqRegistration,
) -> Result<()> {
    ctx.current()
        .thread_local()
        .register_rseq(registration)
        .map_err(rseq_registration_error)
}

/// 从本线程本地状态注销 rseq 注册区。
fn unregister_current_thread_rseq(
    ctx: &SyscallContext,
    registration: RseqRegistration,
) -> Result<()> {
    ctx.current()
        .thread_local()
        .unregister_rseq(registration)
        .map_err(rseq_registration_error)
}

/// 把线程本地 rseq 状态冲突映射成用户态可见 errno。
fn rseq_registration_error(err: RseqRegistrationError) -> Error {
    match err {
        RseqRegistrationError::AddressOrLengthMismatch => Error::new(Errno::EINVAL),
        RseqRegistrationError::SignatureMismatch => Error::new(Errno::EPERM),
        RseqRegistrationError::AlreadyRegistered => Error::new(Errno::EBUSY),
    }
}

/// 注册时初始化用户态 rseq 区域中的内核可写字段。
fn reset_rseq_user_area(vm_space: &VmSpace, registration: RseqRegistration) -> Result<()> {
