impl DispatchRequest {
    /// 从块层提交对象建立第一轮调度请求。
    fn new(bio: SubmittedBio) -> Self {
        Self {
            bio,
            retries: 0,
            last_resource_release_epoch: TRACE_RESOURCE_RELEASE_EPOCH.load(Ordering::Acquire),
        }
    }

    /// 返回块请求操作类型。
