        self.bio.type_()
    }

    /// 取出内部 BIO，用于不进入设备队列的立即完成路径。
    fn into_bio(self) -> SubmittedBio {
        self.bio
    }

    /// 返回该请求经历过的资源型重试次数。
    fn retries(&self) -> usize {
        self.retries
    }

    /// 返回上一次资源型提交失败时观察到的资源释放序号。
    fn last_resource_release_epoch(&self) -> usize {
        self.last_resource_release_epoch
    }

    /// 把请求转换为下一轮资源重试状态。
    fn into_retry(mut self, resource_release_epoch: usize) -> Self {
        self.retries = self
            .retries
            .checked_add(1)
            .expect("virtio-blk dispatch retry counter overflow");
        self.last_resource_release_epoch = resource_release_epoch;
        self
    }
}

