/// 链表只保存页起始物理地址；缓存页入链时交出 `Slab` 句柄，出链时恢复句柄。
#[derive(Debug)]
struct SlabPageList<const SLOT_SIZE: usize> {
    head: Option<PhysAddr>,
    tail: Option<PhysAddr>,
    len: usize,
}

impl<const SLOT_SIZE: usize> SlabPageList<SLOT_SIZE> {
    /// 创建空链表。
    const fn new() -> Self {
        Self {
            head: None,
            tail: None,
            len: 0,
        }
    }

    /// 返回链表节点数。
    const fn len(&self) -> usize {
        self.len
    }

    /// 把一个缓存页放到链表头。
    fn push_front(&mut self, mut slab: Slab<SLOT_SIZE>, list_id: usize) {
        let paddr = slab.start_paddr();
        #[cfg(not(feature = "heap-slab256-watch"))]
        let _ = list_id;
        debug_assert!(
            !self.contains(paddr),
            "slab page inserted twice into the same slab list"
        );
        let old_head = self.head;

        slab.meta_mut().set_prev_slab(None);
        slab.meta_mut().set_next_slab(old_head);

        if let Some(old_head) = old_head {
            Self::update_prev(old_head, Some(paddr));
        } else {
            self.tail = Some(paddr);
        }

        self.head = Some(paddr);

