/// 块设备请求提交接口。
pub trait BlockDevice: Send + Sync + Any + Debug {
    /// 返回用于向下转型的 `Any` 视图。
    fn as_any(&self) -> &dyn Any;

    /// 将一个 `SubmittedBio` 入队到设备队列。
    ///
    /// 返回 `Ok(())` 后，请求所有权转移给设备实现；设备必须在同步路径、工作线程
