    pub fn downcast_ref<T: BlockDevice>(&self) -> Option<&T> {
        self.as_any().downcast_ref::<T>()
    }

    /// 发起一次设备级写回同步，并等待其完成。
    pub fn sync(&self) -> Result<BioStatus, BioEnqueueError> {
        let bio = Bio::try_new_empty(BioType::Flush, Sid::new(0))?;
        bio.submit_and_wait(self)
    }
