ENTRY(_start)

KERNEL_LMA = @KERNEL_LMA@;
KERNEL_VMA_OFFSET = @KERNEL_VMA_OFFSET@;
KERNEL_VMA = KERNEL_VMA_OFFSET + KERNEL_LMA;

SECTIONS
{
    /* `.boot` 段放在物理装载地址。 */
    . = KERNEL_LMA;
    __kernel_lma_start = .;
    __kernel_start = . + KERNEL_VMA_OFFSET;

    __boot_reclaim_lma_start = .;
    __boot_reclaim_start = . + KERNEL_VMA_OFFSET;
    .boot.reclaim : AT(ADDR(.boot.reclaim)) {
        KEEP(*(.boot.entry))
        KEEP(*(.boot))
        KEEP(*(.boot.text))
        KEEP(*(.boot.pagetable))
        KEEP(*(.boot.data))
        . = ALIGN(4096);
    }
    __boot_reclaim_lma_end = .;
    __boot_reclaim_end = . + KERNEL_VMA_OFFSET;

    __boot_stack_lma_start = .;
    __boot_stack_start = . + KERNEL_VMA_OFFSET;
    .boot.stack (NOLOAD) : AT(ADDR(.boot.stack)) {
        KEEP(*(.boot.stack))
        . = ALIGN(4096);
    }
    __boot_stack_lma_end = .;
    __boot_stack_end = . + KERNEL_VMA_OFFSET;

    __kernel_runtime_lma_start = .;
    __kernel_runtime_start = . + KERNEL_VMA_OFFSET;

    /* 内核主体放到高虚拟地址。 */
    . += KERNEL_VMA_OFFSET;

    .text : AT(ADDR(.text) - KERNEL_VMA_OFFSET) {
        *(.text.hal.entry .text.hal.entry.*)
        *(.text.hal.trap .text.hal.trap.*)
        . = ALIGN(4096);
        *(.text.hal.trap.vector .text.hal.trap.vector.*)
        *(.text .text.*)
    }

    .rodata : AT(ADDR(.rodata) - KERNEL_VMA_OFFSET) {
        *(.srodata .srodata.*)
        *(.rodata .rodata.*)
    }

    .data : AT(ADDR(.data) - KERNEL_VMA_OFFSET) {
        *(.sdata .sdata.*)
        *(.sdata2 .sdata2.*)
        *(.data .data.*)
    }

    .cpu_local : AT(ADDR(.cpu_local) - KERNEL_VMA_OFFSET) {
        . = ALIGN(16);
        __cpu_local_start = .;
        *(.cpu_local .cpu_local.*)
        __cpu_local_end = .;
    }

    .got : AT(ADDR(.got) - KERNEL_VMA_OFFSET) {
        *(.got .got.*)
        *(.got.plt .got.plt.*)
    }

    .bss (NOLOAD) : AT(ADDR(.bss) - KERNEL_VMA_OFFSET) {
        . = ALIGN(16);
        __bss_start = .;
        *(.sbss .sbss.*)
        *(.sbss2 .sbss2.*)
        *(.bss .bss.*)
        *(COMMON)
        __bss_end = .;
    }

    .hal_extable : AT(ADDR(.hal_extable) - KERNEL_VMA_OFFSET) {
        . = ALIGN(8);
        __hal_ex_table_start = .;
        KEEP(*(.hal.ex_table))
        __hal_ex_table_end = .;
    }

    __kernel_end = .;
    __kernel_lma_end = __kernel_end - KERNEL_VMA_OFFSET;
}

