/// inode 类型
#[repr(u16)]
#[derive(Copy, Clone, Debug, Eq, PartialEq)]
pub enum InodeType {
    Unknown = 0o000000,
    NamedPipe = 0o010000,
    CharDevice = 0o020000,
    Dir = 0o040000,
    BlockDevice = 0o060000,
    File = 0o100000,
    SymLink = 0o120000,
    Socket = 0o140000,
}

impl InodeType {
    /// 是否支持读
    pub const fn support_read(self) -> bool {
        matches!(
            self,
            Self::File | Self::Socket | Self::CharDevice | Self::BlockDevice
        )
    }

    /// 是否支持写
    pub const fn support_write(self) -> bool {
        matches!(
            self,
            Self::File | Self::Socket | Self::CharDevice | Self::BlockDevice
        )
    }

    /// 是否是普通文件。
    pub const fn is_regular_file(self) -> bool {
        matches!(self, Self::File)
    }

    /// 是否是目录。
    pub const fn is_directory(self) -> bool {
        matches!(self, Self::Dir)
    }

    /// 是否是设备节点。
    pub const fn is_device(self) -> bool {
        matches!(self, Self::BlockDevice | Self::CharDevice)
    }

    /// 从 syscall `mode` 的 type bits 解析为 `InodeType`
    pub fn from_raw_mode(mut mode: u16) -> Result<Self> {
        const TYPE_MASK: u16 = 0o170000;
        mode &= TYPE_MASK;

        // 约定：mode==0 视为普通文件，例如仅传权限位的创建场景。
        if mode == 0 {
            return Ok(Self::File);
        }

        match mode {
            0o010000 => Ok(Self::NamedPipe),
            0o020000 => Ok(Self::CharDevice),
            0o040000 => Ok(Self::Dir),
            0o060000 => Ok(Self::BlockDevice),
            0o100000 => Ok(Self::File),
            0o120000 => Ok(Self::SymLink),
            0o140000 => Ok(Self::Socket),
            _ => Err(Error::with_message(Errno::EINVAL, "invalid file type")),
        }
    }
}

