pub fn dispatch_user_syscall(user_mode: &mut UserMode) -> SyscallOutcome {
    // 不变量：syscall 只能由“正在运行的用户线程”触发。
    let current = Thread::current().expect("user syscall requires a current thread");

    // ABI：riscv64/loongarch64 均使用 a7=nr, a0..a5=args, a0=ret。
    let req = {
        let regs = user_mode.context_mut().general_regs_mut();
        SyscallRequest::new(
            regs.a7,
            [regs.a0, regs.a1, regs.a2, regs.a3, regs.a4, regs.a5],
        )
    };

    let user_ip = user_mode.context().instruction_pointer();
    let user_sp = user_mode.context().stack_pointer();
    match req.nr {
        SYS_EXIT | SYS_EXIT_GROUP => {
            let name = if req.nr == SYS_EXIT_GROUP {
                "exit_group"
            } else {
                "exit"
            };
            let code = req.args.raw(0);
            let args = req.args.raw_array();
            current.record_syscall_entry(req.nr, args, user_ip, user_sp);
            crate::runner_timeout::record_syscall_entry(req.nr, name, args);
            if req.nr == SYS_EXIT_GROUP {
                let process = current
                    .user_process()
                    .expect("exit_group requires a user process");
                process.mark_exited(ExitStatus::from_exit_code(code));
            }
            current.record_syscall_outcome(ThreadSyscallOutcome::Exit { code });
            return SyscallOutcome::Exit { code };
        }
        _ => {}
    }

    let root_vmar = current
        .user_root_vmar()
        .expect("user syscall requires a user thread");
    let ctx = SyscallContext::new(current, root_vmar, user_sp);
    let flow = match table::lookup_meta(req.nr) {
        Some(meta) => {
            log_syscall_entry(&ctx, req, meta.name, user_ip);
            match meta.handler {
                Some(handler) => handler(&ctx, req.args),
                None => unimplemented::dispatch_enosys(req, meta.name),
            }
