            log_syscall_entry(&ctx, req, "out_of_range", user_ip);
            unimplemented::dispatch_enosys(req, "out_of_range")
        }
    };

    match flow {
        SyscallControlFlow::Continue(res) => {
            if let Err(err) = res {
